在 C# 中实现工厂模式（Factory Pattern）有多种方式，这里介绍几种常见的实现方法。

## 1. 简单工厂模式（Simple Factory）

```csharp
// 产品接口
public interface IProduct
{
    string GetName();
}

// 具体产品A
public class ProductA : IProduct
{
    public string GetName() => "Product A";
}

// 具体产品B
public class ProductB : IProduct
{
    public string GetName() => "Product B";
}

// 简单工厂
public class SimpleFactory
{
    public IProduct CreateProduct(string type)
    {
        switch (type)
        {
            case "A":
                return new ProductA();
            case "B":
                return new ProductB();
            default:
                throw new ArgumentException("Invalid product type");
        }
    }
}

// 使用示例
class Program
{
    static void Main()
    {
        var factory = new SimpleFactory();
        var product = factory.CreateProduct("A");
        Console.WriteLine(product.GetName()); // 输出: Product A
    }
}
```

## 2. 工厂方法模式（Factory Method）

```csharp
// 抽象工厂
public abstract class Creator
{
    public abstract IProduct FactoryMethod();
}

// 具体工厂A
public class CreatorA : Creator
{
    public override IProduct FactoryMethod() => new ProductA();
}

// 具体工厂B
public class CreatorB : Creator
{
    public override IProduct FactoryMethod() => new ProductB();
}

// 使用示例
class Program
{
    static void Main()
    {
        Creator creator = new CreatorA();
        IProduct product = creator.FactoryMethod();
        Console.WriteLine(product.GetName()); // 输出: Product A
    }
}
```

## 3. 抽象工厂模式（Abstract Factory）

```csharp
// 抽象产品族
public interface IButton
{
    void Render();
}

public interface ITextBox
{
    void Render();
}

// 具体产品
public class WindowsButton : IButton
{
    public void Render() => Console.WriteLine("Windows Button");
}

public class MacButton : IButton
{
    public void Render() => Console.WriteLine("Mac Button");
}

public class WindowsTextBox : ITextBox
{
    public void Render() => Console.WriteLine("Windows TextBox");
}

public class MacTextBox : ITextBox
{
    public void Render() => Console.WriteLine("Mac TextBox");
}

// 抽象工厂
public interface IUIFactory
{
    IButton CreateButton();
    ITextBox CreateTextBox();
}

// 具体工厂
public class WindowsFactory : IUIFactory
{
    public IButton CreateButton() => new WindowsButton();
    public ITextBox CreateTextBox() => new WindowsTextBox();
}

public class MacFactory : IUIFactory
{
    public IButton CreateButton() => new MacButton();
    public ITextBox CreateTextBox() => new MacTextBox();
}

// 使用示例
class Program
{
    static void Main()
    {
        IUIFactory factory = new WindowsFactory();
        var button = factory.CreateButton();
        var textBox = factory.CreateTextBox();
        button.Render();   // 输出: Windows Button
        textBox.Render();  // 输出: Windows TextBox
    }
}
```

## 4. 使用泛型的工厂模式

```csharp
public class GenericFactory<T> where T : IProduct, new()
{
    public T CreateProduct() => new T();
}

// 使用示例
var factory = new GenericFactory<ProductA>();
var product = factory.CreateProduct();
Console.WriteLine(product.GetName()); // 输出: Product A
```

## 5. 使用依赖注入的工厂模式

```csharp
public interface IProductFactory
{
    IProduct CreateProduct(string type);
}

public class ProductFactory : IProductFactory
{
    private readonly Dictionary<string, Func<IProduct>> _factories;

    public ProductFactory()
    {
        _factories = new Dictionary<string, Func<IProduct>>
        {
            { "A", () => new ProductA() },
            { "B", () => new ProductB() }
        };
    }

    public IProduct CreateProduct(string type)
    {
        if (_factories.TryGetValue(type, out var factory))
        {
            return factory();
        }
        throw new ArgumentException($"Unknown product type: {type}");
    }
}
```

## 选择建议

- **简单工厂**：适合产品类型较少且不经常变化的场景
- **工厂方法**：适合需要扩展新产品类型的场景
- **抽象工厂**：适合创建一系列相关或相互
